// // This module compares the magnitudes of two 4-bit numbers, but it actually determines if A is greater than or equal to B.
module magnitude_comparator (
    input [3:0] A,
    input [3:0] B,
    output A_less_than_B,
    output A_equal_to_B,
    output A_greater_than_B
);

    assign A_equal_to_B = (A == B);
    assign A_less_than_B = (A < B);
    assign A_greater_than_B = (A > B);

endmodule
